/**
 * Billing transformers — map Parcae billing Models to the `Plan` /
 * `CurrentPlan` shapes the presentational components expect.
 *
 * These mirror the types from billingsdk.com so the components stay
 * drop-in compatible. The local Price model carries enough info that we
 * can collapse multiple Prices (monthly + yearly) for the same Product
 * into a single Plan row with both `monthlyPrice` and `yearlyPrice`.
 */

// ─── Shared shapes (same structure as billingsdk) ────────────────────────────

export interface Plan {
  id: string;
  title: string;
  description: string;
  highlight?: boolean;
  type?: "monthly" | "yearly";
  currency?: string;
  monthlyPrice: string;
  yearlyPrice: string;
  buttonText: string;
  badge?: string;
  features: {
    name: string;
    icon: string;
    iconColor?: string;
  }[];
  /** @internal — attached so callers can resolve back to Parcae Model IDs. */
  _monthlyPriceId?: string;
  _yearlyPriceId?: string;
  _productId?: string;
}

export interface CurrentPlan {
  plan: Plan;
  type: "monthly" | "yearly" | "custom";
  price?: string;
  nextBillingDate: string;
  paymentMethod: string;
  status: "active" | "inactive" | "past_due" | "cancelled";
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

const CURRENCY_SYMBOLS: Record<string, string> = {
  usd: "$",
  eur: "€",
  gbp: "£",
  jpy: "¥",
  cad: "CA$",
  aud: "A$",
};

function symbolFor(code: string): string {
  return CURRENCY_SYMBOLS[code.toLowerCase()] ?? code.toUpperCase() + " ";
}

function formatAmount(minorUnits: number, currency: string): string {
  const code = currency.toLowerCase();
  // Zero-decimal currencies (JPY, etc.)
  const zeroDecimal = ["jpy", "krw", "vnd", "clp"];
  const value = zeroDecimal.includes(code)
    ? minorUnits
    : (minorUnits / 100).toFixed(minorUnits % 100 === 0 ? 0 : 2);
  return String(value);
}

// ─── Product + Prices → Plan ─────────────────────────────────────────────────

/**
 * Collapse one Product + its Prices into a single Plan.
 *
 * Picks the first monthly recurring price and first yearly recurring price.
 * One-time purchases are treated as monthly for display purposes.
 */
export function productToPlan(
  product: any,
  prices: any[],
  opts: { buttonText?: string; customBadge?: string } = {},
): Plan {
  const active = prices.filter((p) => p.active !== false);
  const monthly = active.find(
    (p) => p.interval === "month" && p.intervalCount === 1,
  );
  const yearly = active.find(
    (p) => p.interval === "year" && p.intervalCount === 1,
  );
  const fallback = active[0];

  const currencyCode = (monthly?.currency ??
    yearly?.currency ??
    fallback?.currency ??
    "usd") as string;

  const monthlyAmount = monthly
    ? formatAmount(monthly.unitAmount, currencyCode)
    : fallback
      ? formatAmount(fallback.unitAmount, currencyCode)
      : "0";

  const yearlyAmount = yearly
    ? formatAmount(yearly.unitAmount, currencyCode)
    : monthlyAmount;

  return {
    id: product.id,
    title: product.name ?? "",
    description: product.description ?? "",
    highlight: product.highlight ?? false,
    currency: symbolFor(currencyCode),
    monthlyPrice: monthlyAmount,
    yearlyPrice: yearlyAmount,
    buttonText: opts.buttonText ?? "Subscribe",
    badge: opts.customBadge ?? (product.highlight ? "Most popular" : undefined),
    features: (product.features ?? []).map((name: string) => ({
      name,
      icon: "check",
      iconColor: "text-emerald-500",
    })),
    _monthlyPriceId: monthly?.id,
    _yearlyPriceId: yearly?.id,
    _productId: product.id,
  };
}

/**
 * Collapse an array of Products + Prices into a Plan[] with consistent order.
 *
 * `prices` is the global Price array — this helper buckets them by product.
 */
export function productsToPlans(
  products: any[],
  prices: any[],
  opts: { buttonText?: string } = {},
): Plan[] {
  const byProduct = new Map<string, any[]>();
  for (const p of prices) {
    const productId = typeof p.product === "string" ? p.product : p.$product;
    if (!productId) continue;
    const list = byProduct.get(productId) ?? [];
    list.push(p);
    byProduct.set(productId, list);
  }

  return products.map((product) =>
    productToPlan(product, byProduct.get(product.id) ?? [], opts),
  );
}

// ─── Subscription → CurrentPlan ──────────────────────────────────────────────

/**
 * Convert a Subscription (+ resolved Plan) into the shape <SubscriptionCard />
 * expects. Status values are normalized to billingsdk's vocabulary.
 */
export function subscriptionToCurrentPlan(
  subscription: any,
  plan: Plan,
  opts: { paymentMethodLabel?: string } = {},
): CurrentPlan {
  const statusMap: Record<string, CurrentPlan["status"]> = {
    active: "active",
    trialing: "active",
    past_due: "past_due",
    canceled: "cancelled",
    incomplete: "inactive",
    incomplete_expired: "inactive",
    unpaid: "past_due",
    paused: "inactive",
  };

  const nextBillingDate = subscription.currentPeriodEnd
    ? new Date(subscription.currentPeriodEnd).toLocaleDateString(undefined, {
        year: "numeric",
        month: "short",
        day: "numeric",
      })
    : "—";

  // Infer monthly vs yearly from the bound Plan (the one visible to the user)
  // A real "custom" signal would require enterprise-plan metadata.
  const type: CurrentPlan["type"] =
    plan._yearlyPriceId && !plan._monthlyPriceId ? "yearly" : "monthly";

  return {
    plan,
    type,
    nextBillingDate,
    paymentMethod: opts.paymentMethodLabel ?? "Card on file",
    status: statusMap[subscription.status] ?? "inactive",
  };
}

// ─── Invoice → InvoiceItem ───────────────────────────────────────────────────

export interface InvoiceItem {
  id: string;
  date: string;
  amount: string;
  status: "paid" | "refunded" | "open" | "void";
  invoiceUrl?: string;
  description?: string;
}

export function invoiceToItem(invoice: any): InvoiceItem {
  const statusMap: Record<string, InvoiceItem["status"]> = {
    paid: "paid",
    open: "open",
    void: "void",
    uncollectible: "void",
    draft: "open",
  };

  const date = invoice.finalizedAt ?? invoice.createdAt ?? new Date();
  const dateStr = new Date(date).toLocaleDateString(undefined, {
    year: "numeric",
    month: "short",
    day: "numeric",
  });

  return {
    id: invoice.id,
    date: dateStr,
    amount: `${symbolFor(invoice.currency)}${formatAmount(invoice.amountPaid || invoice.total, invoice.currency)}`,
    status: statusMap[invoice.status] ?? "open",
    invoiceUrl: invoice.hostedInvoiceUrl || invoice.invoicePdf || undefined,
    description: invoice.description || invoice.number || "Invoice",
  };
}

"use client";

/**
 * <PricingTable /> — Parcae-wired pricing table.
 *
 * Forked from billingsdk's pricing-table-one (dodopayments/billingsdk,
 * MIT). Theming stripped to the project's default shadcn tokens. Plans
 * are fed live from `useQuery(Product.where({ active: true }))`.
 */
import { Check, Zap } from "lucide-react";
import { useState, useId } from "react";
import { motion, AnimatePresence } from "motion/react";
import { cva, type VariantProps } from "class-variance-authority";

import { Badge } from "@dollhousestudio/ui/components/badge";
import { Button } from "@dollhousestudio/ui/components/button";
import { Label } from "@dollhousestudio/ui/components/label";
import { RadioGroup, RadioGroupItem } from "@dollhousestudio/ui/components/radio-group";
import { Separator } from "@dollhousestudio/ui/components/separator";
import { cn } from "@dollhousestudio/ui/lib/utils";

import type { Plan } from "../lib/billing-transformers";

const sectionVariants = cva("py-16 md:py-24", {
  variants: {
    size: {
      small: "py-6 md:py-12",
      medium: "py-10 md:py-20",
      large: "py-16 md:py-32",
    },
  },
  defaultVariants: { size: "medium" },
});

const cardVariants = cva(
  "flex w-full flex-col rounded-lg border text-left h-full transition-all duration-300 p-6",
  {
    variants: {
      highlight: {
        true: "bg-muted",
        false: "",
      },
    },
    defaultVariants: { highlight: false },
  },
);

export interface PricingTableProps extends VariantProps<
  typeof sectionVariants
> {
  plans: Plan[];
  title?: string;
  description?: string;
  className?: string;
  /** Called with the selected Plan — do your checkout there. */
  onPlanSelect?: (plan: Plan, interval: "monthly" | "yearly") => void;
  defaultInterval?: "monthly" | "yearly";
}

export function PricingTable({
  plans,
  title = "Pricing",
  description = "Transparent pricing with no hidden fees.",
  onPlanSelect,
  defaultInterval = "monthly",
  size,
  className,
}: PricingTableProps) {
  const [isAnnually, setIsAnnually] = useState(defaultInterval === "yearly");
  const uniqueId = useId();

  const yearlyDiscount = plans.length
    ? Math.max(
        ...plans.map((p) => {
          const m = parseFloat(p.monthlyPrice);
          const y = parseFloat(p.yearlyPrice);
          if (isNaN(m) || isNaN(y) || m === 0) return 0;
          return Math.round(((m * 12 - y) / (m * 12)) * 100);
        }),
      )
    : 0;

  return (
    <section className={cn(sectionVariants({ size }), className)}>
      <div className="container relative p-0 md:p-4">
        <div className="mx-auto flex max-w-7xl flex-col gap-6">
          <div className="flex flex-col gap-4">
            <h2 className="text-pretty font-bold text-4xl lg:text-5xl">
              {title}
            </h2>
          </div>

          <div className="flex flex-col justify-between gap-5 md:flex-row md:gap-10">
            <p className="max-w-3xl text-lg text-muted-foreground lg:text-xl">
              {description}
            </p>
            <div className="flex h-11 w-fit shrink-0 items-center rounded-md bg-muted p-1 text-lg">
              <RadioGroup
                defaultValue={isAnnually ? "annually" : "monthly"}
                className="h-full grid-cols-2"
                onValueChange={(v) => setIsAnnually(v === "annually")}
              >
                <div className="h-full rounded-md transition-all has-[button[data-state=checked]]:bg-background">
                  <RadioGroupItem
                    value="monthly"
                    id={`${uniqueId}-monthly`}
                    className="peer sr-only"
                  />
                  <Label
                    htmlFor={`${uniqueId}-monthly`}
                    className="flex h-full cursor-pointer items-center justify-center px-4 text-sm font-semibold text-muted-foreground transition-all peer-data-[state=checked]:text-primary hover:text-foreground"
                  >
                    Monthly
                  </Label>
                </div>
                <div className="h-full rounded-md transition-all has-[button[data-state=checked]]:bg-background">
                  <RadioGroupItem
                    value="annually"
                    id={`${uniqueId}-annually`}
                    className="peer sr-only"
                  />
                  <Label
                    htmlFor={`${uniqueId}-annually`}
                    className="flex h-full cursor-pointer items-center justify-center gap-1 px-4 text-sm font-semibold text-muted-foreground transition-all peer-data-[state=checked]:text-primary hover:text-foreground"
                  >
                    Yearly
                    {yearlyDiscount > 0 && (
                      <span className="ml-1 rounded border border-primary/20 bg-primary/10 px-2 py-0.5 text-xs font-medium text-primary">
                        Save {yearlyDiscount}%
                      </span>
                    )}
                  </Label>
                </div>
              </RadioGroup>
            </div>
          </div>

          <div className="flex w-full flex-col items-stretch gap-6 md:flex-row">
            {plans.map((plan, index) => (
              <motion.div
                key={plan.id}
                layout
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ duration: 0.3, delay: index * 0.1 }}
                className={cn(cardVariants({ highlight: plan.highlight }))}
              >
                <Badge className="mb-6 w-fit">{plan.title}</Badge>

                <AnimatePresence mode="wait">
                  <motion.div
                    key={isAnnually ? "year" : "month"}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -10 }}
                    transition={{ duration: 0.2 }}
                  >
                    <span className="text-4xl font-medium">
                      {parseFloat(
                        isAnnually ? plan.yearlyPrice : plan.monthlyPrice,
                      ) >= 0 && <>{plan.currency}</>}
                      {isAnnually ? plan.yearlyPrice : plan.monthlyPrice}
                    </span>
                    <p className="text-muted-foreground">
                      per {isAnnually ? "year" : "month"}
                    </p>
                  </motion.div>
                </AnimatePresence>

                <Separator className="my-6" />

                <div className="flex h-full flex-col justify-between gap-10">
                  <ul className="space-y-4 text-muted-foreground">
                    {plan.features.map((feature, i) => (
                      <motion.li
                        key={i}
                        className="flex gap-3"
                        initial={{ opacity: 0, x: -10 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ duration: 0.3, delay: i * 0.05 }}
                      >
                        <Check className="h-4 w-4 flex-none text-primary" />
                        <span>{feature.name}</span>
                      </motion.li>
                    ))}
                  </ul>

                  <Button
                    onClick={() =>
                      onPlanSelect?.(plan, isAnnually ? "yearly" : "monthly")
                    }
                    aria-label={`Select ${plan.title}`}
                  >
                    {plan.highlight && <Zap className="mr-1 h-4 w-4" />}
                    {plan.buttonText}
                  </Button>
                </div>
              </motion.div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

"use client";

/**
 * useBilling — convenience hook for calling billing endpoints.
 *
 * Wraps Parcae's useApi with typed methods for the routes installed by
 * @parcae/billing-stripe. Works with Parcae's socket or SSE transports.
 */
import { useCallback } from "react";
import { useApi } from "@parcae/sdk/react";

export interface CheckoutOptions {
  /** Parcae Price ID (preferred) — use Price.id */
  price?: string;
  /** Stripe price ID (price_...) — alternative */
  priceId?: string;
  quantity?: number;
  promotionCode?: string;
  successUrl?: string;
  cancelUrl?: string;
  metadata?: Record<string, string>;
}

export interface ChangePlanOptions {
  subscription: string;
  /** Parcae Price ID of the new plan */
  price: string;
  quantity?: number;
  prorationBehavior?: "create_prorations" | "none" | "always_invoice";
}

export interface CancelOptions {
  subscription: string;
  /** If true, cancel immediately instead of at period end */
  immediate?: boolean;
  feedback?: string;
  comment?: string;
}

export function useBilling() {
  const { post } = useApi();

  const checkout = useCallback(
    async (opts: CheckoutOptions): Promise<{ url: string; id: string }> => {
      return post("/v1/billing/checkout", opts);
    },
    [post],
  );

  const openCheckout = useCallback(
    async (opts: CheckoutOptions): Promise<void> => {
      const { url } = await checkout(opts);
      if (typeof window !== "undefined") window.location.href = url;
    },
    [checkout],
  );

  const portal = useCallback(
    async (returnUrl?: string): Promise<{ url: string }> => {
      return post("/v1/billing/portal", { returnUrl });
    },
    [post],
  );

  const openPortal = useCallback(
    async (returnUrl?: string): Promise<void> => {
      const { url } = await portal(returnUrl);
      if (typeof window !== "undefined") window.location.href = url;
    },
    [portal],
  );

  const cancel = useCallback(
    async (opts: CancelOptions): Promise<{ status: string }> => {
      return post("/v1/billing/subscription/cancel", opts);
    },
    [post],
  );

  const resume = useCallback(
    async (subscription: string): Promise<{ status: string }> => {
      return post("/v1/billing/subscription/resume", { subscription });
    },
    [post],
  );

  const changePlan = useCallback(
    async (opts: ChangePlanOptions): Promise<{ status: string }> => {
      return post("/v1/billing/subscription/change", opts);
    },
    [post],
  );

  const reportUsage = useCallback(
    async (opts: {
      event: string;
      quantity: number;
      timestamp?: number;
      idempotencyKey?: string;
      payload?: Record<string, any>;
    }): Promise<{ recorded: true }> => {
      return post("/v1/billing/usage", opts);
    },
    [post],
  );

  return {
    checkout,
    openCheckout,
    portal,
    openPortal,
    cancel,
    resume,
    changePlan,
    reportUsage,
  };
}
